INSERT INTO public.agent_sql_runs (id,message_id,executed_sql,bq_result,created_at) VALUES
('da80e38a-bcea-4347-aa56-b7285e5510ab','3421fad6-6ce2-4b51-b3bd-c25544516a86','WITH daily AS (SELECT branch, submission_date, COUNT(DISTINCT contact) AS regs FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE submission_date BETWEEN DATE_SUB(CURRENT_DATE(), INTERVAL 13 DAY) AND CURRENT_DATE() GROUP BY branch, submission_date), weekly AS (SELECT branch, CASE WHEN submission_date BETWEEN DATE_SUB(CURRENT_DATE(), INTERVAL 6 DAY) AND CURRENT_DATE() THEN ''this_week'' WHEN submission_date BETWEEN DATE_SUB(CURRENT_DATE(), INTERVAL 13 DAY) AND DATE_SUB(CURRENT_DATE(), INTERVAL 7 DAY) THEN ''last_week'' END AS week_label, SUM(regs) AS weekly_regs FROM daily GROUP BY branch, week_label), pivoted AS (SELECT branch, SUM(CASE WHEN week_label = ''this_week'' THEN weekly_regs ELSE 0 END) AS this_week_regs, SUM(CASE WHEN week_label = ''last_week'' THEN weekly_regs ELSE 0 END) AS last_week_regs, SUM(CASE WHEN week_label = ''this_week'' THEN weekly_regs ELSE 0 END) - SUM(CASE WHEN week_label = ''last_week'' THEN weekly_regs ELSE 0 END) AS drop_count FROM weekly GROUP BY branch) SELECT branch, this_week_regs, last_week_regs, drop_count FROM pivoted ORDER BY drop_count ASC','{"schema":{"fields":[{"name":"branch","type":"STRING","mode":"NULLABLE"},{"name":"this_week_regs","type":"INTEGER","mode":"NULLABLE"},{"name":"last_week_regs","type":"INTEGER","mode":"NULLABLE"},{"name":"drop_count","type":"INTEGER","mode":"NULLABLE"}]},"rows":[{"f":[{"v":"Chawkbazar Branch"},{"v":"475"},{"v":"646"},{"v":"-171"}]},{"f":[{"v":"Moghbazar Branch"},{"v":"167"},{"v":"269"},{"v":"-102"}]},{"f":[{"v":"Mirpur Branch"},{"v":"472"},{"v":"572"},{"v":"-100"}]},{"f":[{"v":"Panthapath Branch"},{"v":"153"},{"v":"251"},{"v":"-98"}]},{"f":[{"v":null},{"v":"220"},{"v":"315"},{"v":"-95"}]},{"f":[{"v":"Uttara Branch"},{"v":"635"},{"v":"716"},{"v":"-81"}]}],"jobComplete":true}','2026-03-18 07:59:44.694301+00'),
